// MakeShop 회원 목록에서 D+1/3/7/14/21 발송 대상 분류
var raw = $input.first().json;

// MakeShop list 응답은 객체일 수 있음 -> 배열 변환
var members = [];
if (raw && raw.list) {
  if (Array.isArray(raw.list)) {
    members = raw.list;
  } else if (typeof raw.list === 'object') {
    members = Object.values(raw.list);
  }
}

// 오늘 날짜 (KST)
var now = new Date();
var kstNow = new Date(now.getTime() + 9 * 60 * 60 * 1000);
var todayStr = kstNow.toISOString().slice(0, 10);
var todayMs = new Date(todayStr + 'T00:00:00Z').getTime();

// 단계 정의
var steps = [
  { day: 1, key: 'D1' },
  { day: 3, key: 'D3' },
  { day: 7, key: 'D7' },
  { day: 14, key: 'D14' },
  { day: 21, key: 'D21' }
];

// 이메일 콘텐츠 정의
