  },
  D21: {
    subject: '[프레스코21] 다음에 도전해볼 재료 알려드릴게요',
    greeting: '{name}님, 꽃 공예가 재미있으셨나요?',
    body: '처음 시도한 꽃 공예가 재미있으셨다면, 다음 단계로 넘어가 볼까요?<br><br><strong>추천 카테고리:</strong><br>- 시즌 한정 재료 (매달 새로운 컬러와 소재)<br>- 고급 도구 세트 (작품 퀄리티 UP)<br>- DIY 키트 (선물용으로도 인기)<br><br>프레스코21은 꽃 공예를 사랑하는 분들과 함께합니다.',
    ctaUrl: 'https://www.foreverlove.co.kr/',
    ctaText: '프레스코21 둘러보기'
  }
};

// HTML 템플릿 생성 함수
function buildHtml(tpl, name) {
  var greeting = tpl.greeting.replace('{name}', name);
  var html = '<div style="max-width:600px;margin:0 auto;font-family:Pretendard,Apple SD Gothic Neo,Malgun Gothic,sans-serif;color:#2b3d2f;">';
  html += '<div style="background:#b4c6ab;padding:20px;text-align:center;">';
  html += '<h1 style="color:#fff;margin:0;font-size:22px;">PRESSCO21</h1>';
  html += '<p style="color:#fff;margin:4px 0 0;font-size:13px;opacity:0.85;">꽃으로노는모든방법</p>';
  html += '</div>';
  html += '<div style="padding:30px 28px;background:#fff;">';
  html += '<p style="font-size:15px;line-height:1.7;margin:0 0 16px;">' + greeting + '</p>';
  html += '<p style="font-size:15px;line-height:1.7;margin:0 0 24px;">' + tpl.body + '</p>';
  html += '<div style="text-align:center;margin:28px 0;">';
  html += '<a href="' + tpl.ctaUrl + '" style="display:inline-block;background:#597051;color:#fff;padding:14px 28px;border-radius:6px;text-decoration:none;font-size:15px;font-weight:500;">' + tpl.ctaText + '</a>';
  html += '</div>';
  html += '</div>';
  html += '<div style="background:#e5eae3;padding:18px 28px;text-align:center;">';
  html += '<p style="font-size:12px;color:#666;margin:0 0 4px;line-height:1.5;">foreverlove.co.kr | 프레스코21</p>';
  html += '<p style="font-size:12px;color:#666;margin:0 0 4px;">서울 송파구 백제고분로7길 28, 2층</p>';
  html += '<p style="font-size:11px;color:#999;margin:6px 0 0;">070-7576-0778 | pressco5755@naver.com</p>';
  html += '</div>';
  html += '</div>';
  return html;
}

// 발송 대상 분류
var results = [];
var maxTotal = 50; // 일일 안전장치

for (var i = 0; i < members.length; i++) {
  if (results.length >= maxTotal) break;

  var m = members[i];
  var email = String(m.email || '').trim();
  var emailRecv = String(m.email_receive || 'Y').toUpperCase();
  var name = String(m.hname || m.name || '').trim();
  var regDate = String(m.reg_date || '').trim();

  // 이메일 없거나 수신거부이면 스킵
  if (!email || email.indexOf('@') < 0) continue;
  if (emailRecv === 'N') continue;
  if (!regDate) continue;

  // 가입일로부터 경과일 계산
  var regDateStr = regDate.slice(0, 10); // yyyy-MM-dd
  var regMs = new Date(regDateStr + 'T00:00:00Z').getTime();
  if (isNaN(regMs)) continue;

  var diffDays = Math.round((todayMs - regMs) / (24 * 60 * 60 * 1000));

  // 해당하는 단계 찾기
  for (var s = 0; s < steps.length; s++) {
    if (diffDays === steps[s].day) {
      var tpl = emailTemplates[steps[s].key];
      var subject = tpl.subject.replace('{name}', name || '고객');
      var htmlBody = buildHtml(tpl, name || '고객');

      results.push({
        json: {
          email: email,
          name: name || '고객',
          userId: String(m.id || ''),
          step: steps[s].key,
          daysSinceJoin: diffDays,
          subject: subject,
          htmlBody: htmlBody,
          regDate: regDateStr
        }
      });
      break;
    }
  }
}

if (results.length === 0) {
  return [{ json: { empty: true, count: 0, totalMembers: members.length, message: '오늘 발송 대상 없음' } }];
}

return results;

// 발송 결과 확인 + 집계
var allItems = $input.all();
var sentData = [];
var failCount = 0;

try {
  sentData = $('단계별 발송 대상 분류').all();
} catch(e) {
  sentData = [];
}

var results = [];
for (var i = 0; i < allItems.length; i++) {
  var item = allItems[i].json;
  var orig = sentData[i] ? sentData[i].json : {};
  var hasError = false;

  if (typeof item.error === 'string' && item.error) {
    hasError = true;
    failCount++;
  } else if (Array.isArray(item.rejected) && item.rejected.length > 0) {
    hasError = true;
    failCount++;
  }

  results.push({
    json: {
      email: orig.email || '',
      name: orig.name || '',
      step: orig.step || '',
      success: !hasError,
      error: hasError ? String(item.error || 'rejected') : ''
    }
  });
}

return results;

// 발송 결과 집계 -> 텔레그램 메시지 생성
var items = $input.all();
var stepCount = { D1: 0, D3: 0, D7: 0, D14: 0, D21: 0 };
var totalSent = 0;
var totalFail = 0;
var failDetails = [];

for (var i = 0; i < items.length; i++) {
  var d = items[i].json;
  if (d.success) {
    totalSent++;
    if (stepCount[d.step] !== undefined) stepCount[d.step]++;
  } else {
    totalFail++;
    failDetails.push(d.name + '(' + d.step + '): ' + (d.error || 'unknown').substring(0, 50));
  }
}

var stepLabels = {
  D1: 'D+1 입문가이드',
  D3: 'D+3 TOP3상품',
  D7: 'D+7 유튜브강의',
  D14: 'D+14 파트너클래스',
  D21: 'D+21 재구매유도'
};

var msg = '\u{1F4E8} 온보딩 이메일 시퀀스 발송 결과\n';
msg += '\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n';
msg += '\u2705 성공: ' + totalSent + '건';
if (totalFail > 0) msg += ' | \u274c 실패: ' + totalFail + '건';
msg += '\n\n';

var hasAny = false;
var stepKeys = ['D1', 'D3', 'D7', 'D14', 'D21'];
for (var s = 0; s < stepKeys.length; s++) {
  var k = stepKeys[s];
  if (stepCount[k] > 0) {
    msg += '\u2022 ' + stepLabels[k] + ': ' + stepCount[k] + '\uBA85\n';
    hasAny = true;
  }
}

if (!hasAny) msg += '(\uBC1C\uC1A1 \uC131\uACF5 \uAC74 \uC5C6\uC74C)\n';

if (failDetails.length > 0) {
  msg += '\n\u26a0\ufe0f \uC2E4\uD328 \uC0C1\uC138:\n';
  for (var f = 0; f < Math.min(failDetails.length, 5); f++) {
    msg += '  - ' + failDetails[f] + '\n';
  }
  if (failDetails.length > 5) msg += '  ... \uC678 ' + (failDetails.length - 5) + '\uAC74';
}

return [{ json: { message: msg, totalSent: totalSent, totalFail: totalFail } }];
